const nav=document.querySelector(".nav"),navLink=document.querySelectorAll(".nav-link"),menu=document.querySelector(".menu-bars"),body=document.querySelector("body");let showMenu=!1;function toggleMenu(){showMenu?(nav.classList.remove("open"),menu.classList.remove("close"),body.classList.remove("darken"),showMenu=!1):(nav.classList.add("open"),menu.classList.add("close"),body.classList.add("darken"),showMenu=!0)}menu.addEventListener("click",toggleMenu);